     6→
     7→const OpinionEditor = ({onClose}) =>{
     8→    const [opinion, setOpinion] = useState('');
     9→    const {session} = useAuth();
    10→    const [isSaving, setIsSaving] = useState(false);
    11→
    12→    const queryClient = useQueryClient();
    13→
    14→    const handleCloseEditor = () =>{
    15→        onClose();
    16→    }
    17→
    18→    const handleClickSave = async(e) =>{
    19→        e.stopPropagation();
    20→        if(isSaving){
    21→            return;
    22→        }
    23→        const formdata = new FormData();
    24→        formdata.append('opinion', opinion)
    25→        
    26→        try {
    27→            setIsSaving(true);
    28→
    29→            const message = await addOpinion(formdata, session?.access_token);
    30→            if(message){
    31→                console.log(message)
    32→            }
    33→            setIsSaving(false)
    34→            queryClient.invalidateQueries(['getOpinions']);
    35→        } catch (error) {
    36→            setIsSaving(false)
    37→            setOpinion('')
    38→            throw new Error('error uploading data')
    39→        } finally {
    40→            setOpinion('')
    41→            onClose();
    42→        }
    43→
    44→    }
    45→
    46→    return(
    47→        <>
    48→        <div className="opinion-editor-parent-container">
    49→            <div className="opinion-editor-container">
